package workloadmanager

type Config struct {
	Port              int
	RuntimeClassName  string
	EnableTLS         bool
	TLSCert           string
	TLSKey            string
	EnableAuth        bool
	Kubeconfig        string
	MasterURL         string
	Namespace         string
	LeaderElection    bool
	LeaderElectionID  string
	MetricsAddr       string
	HealthProbeAddr   string
}

func DefaultConfig() *Config {
	return &Config{
		Port:             8080,
		RuntimeClassName: "",
		EnableTLS:        false,
		EnableAuth:       false,
		LeaderElection:   false,
		LeaderElectionID: "workload-manager-leader",
		MetricsAddr:      ":8081",
		HealthProbeAddr:  ":8082",
	}
}

func (c *Config) Validate() error {
	if c.Port <= 0 || c.Port > 65535 {
		return &ConfigError{Field: "Port", Message: "port must be between 1 and 65535"}
	}
	if c.EnableTLS {
		if c.TLSCert == "" {
			return &ConfigError{Field: "TLSCert", Message: "TLS cert path is required when TLS is enabled"}
		}
		if c.TLSKey == "" {
			return &ConfigError{Field: "TLSKey", Message: "TLS key path is required when TLS is enabled"}
		}
	}
	return nil
}

type ConfigError struct {
	Field   string
	Message string
}

func (e *ConfigError) Error() string {
	return "config error: " + e.Field + " - " + e.Message
}

