)

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":    "healthy",
		"startTime": s.startTime.Format(time.RFC3339),
	})
}

func (s *Server) handleAgentRuntimeCreate(c *gin.Context) {
	var req types.CreateSandboxRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if err := req.Validate(); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if req.Kind != types.AgentRuntimeKind {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid kind, expected AgentRuntime"})
		return
	}

	sessionID := uuid.New().String()
	ctx := c.Request.Context()

	sandboxInfo, err := s.buildSandboxForAgentRuntime(ctx, &req, sessionID)
	if err != nil {
		klog.ErrorS(err, "Failed to build sandbox for AgentRuntime", "name", req.Name, "namespace", req.Namespace)
		if apiErr, ok := err.(api.APIStatus); ok {
			c.JSON(int(apiErr.Status().Code), gin.H{"error": apiErr.Status().Message})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	resp := &types.CreateSandboxResponse{
		SessionID:   sandboxInfo.SessionID,
		SandboxID:   sandboxInfo.SandboxID,
		SandboxName: sandboxInfo.Name,
		EntryPoints: sandboxInfo.EntryPoints,
	}

	c.JSON(http.StatusOK, resp)
}

func (s *Server) handleCodeInterpreterCreate(c *gin.Context) {
	var req types.CreateSandboxRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if err := req.Validate(); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if req.Kind != types.CodeInterpreterKind {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid kind, expected CodeInterpreter"})
		return
	}

	sessionID := uuid.New().String()
	ctx := c.Request.Context()

	sandboxInfo, err := s.buildSandboxForCodeInterpreter(ctx, &req, sessionID)
	if err != nil {
		klog.ErrorS(err, "Failed to build sandbox for CodeInterpreter", "name", req.Name, "namespace", req.Namespace)
		if apiErr, ok := err.(api.APIStatus); ok {
			c.JSON(int(apiErr.Status().Code), gin.H{"error": apiErr.Status().Message})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	resp := &types.CreateSandboxResponse{
		SessionID:   sandboxInfo.SessionID,
		SandboxID:   sandboxInfo.SandboxID,
		SandboxName: sandboxInfo.Name,
		EntryPoints: sandboxInfo.EntryPoints,
	}

	c.JSON(http.StatusOK, resp)
}

func (s *Server) handleDeleteSandbox(c *gin.Context) {
	sessionID := c.Param("sessionId")
	if sessionID == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "session id is required"})
		return
	}

	ctx := c.Request.Context()

	if err := s.deleteSandboxBySessionID(ctx, sessionID); err != nil {
		klog.ErrorS(err, "Failed to delete sandbox", "sessionID", sessionID)
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"status":    "deleted",
		"sessionId": sessionID,
	})
}

func (s *Server) deleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	sandbox, err := s.k8sClient.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		return fmt.Errorf("failed to get sandbox: %w", err)
	}

	if sandbox == nil {
		return nil
	}

	return s.k8sClient.DeleteSandbox(ctx, sandbox.Namespace, sandbox.Name)
}

func respondWithError(c *gin.Context, code int, message string) {
	c.JSON(code, gin.H{"error": message})
}

func respondWithAPIError(c *gin.Context, err error) {
	if apiErr, ok := err.(api.APIStatus); ok {
		c.JSON(int(apiErr.Status().Code), gin.H{
			"error":  apiErr.Status().Message,
			"reason": apiErr.Status().Reason,
		})
		return
	}
	c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
}

