package workloadmanager

import (
	"context"
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"fmt"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/client-go/kubernetes"
	"k8s.io/klog/v2"
)

type Server struct {
	config          *Config
	engine          *gin.Engine
	httpServer      *http.Server
	k8sClient       *K8sClient
	clientset       kubernetes.Interface
	tokenCache      *TokenCache
	authMiddleware  gin.HandlerFunc
	startTime       time.Time
}

func NewServer(cfg *Config) (*Server, error) {
	if err := cfg.Validate(); err != nil {
		return nil, fmt.Errorf("invalid config: %w", err)
	}

	k8sClient, err := NewK8sClient(cfg.Kubeconfig, cfg.MasterURL)
	if err != nil {
		return nil, fmt.Errorf("failed to create k8s client: %w", err)
	}

	if err := k8sClient.Start(context.Background()); err != nil {
		return nil, fmt.Errorf("failed to start k8s client: %w", err)
	}

	gin.SetMode(gin.ReleaseMode)
	if cfg.EnableTLS {
		gin.SetMode(gin.TestMode)
	}

	engine := gin.New()
	engine.Use(gin.Recovery())

	s := &Server{
		config:     cfg,
		engine:     engine,
		k8sClient:  k8sClient,
		clientset:  k8sClient.clientset,
		tokenCache: NewTokenCache(1000, 5*time.Minute),
		startTime:  time.Now(),
	}

	if cfg.EnableAuth {
		s.authMiddleware = s.authMiddlewareFunc()
		engine.Use(s.authMiddleware)
	}

	s.setupRoutes()
	s.httpServer = &http.Server{
		Addr:         fmt.Sprintf(":%d", cfg.Port),
		Handler:      engine,
		ReadTimeout:  30 * time.Second,
		WriteTimeout: 30 * time.Second,
		IdleTimeout:  90 * time.Second,
	}

	return s, nil
}

func (s *Server) Start(ctx context.Context) error {
	klog.InfoS("Starting workload manager server", "port", s.config.Port)

	go func() {
		var err error
		if s.config.EnableTLS {
			err = s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
		} else {
			err = s.httpServer.ListenAndServe()
		}
		if err != nil && err != http.ErrServerClosed {
			klog.ErrorS(err, "Server error")
		}
	}()

	return nil
}

func (s *Server) Shutdown(ctx context.Context) error {
	klog.InfoS("Shutting down workload manager server")
	return s.httpServer.Shutdown(ctx)
}

func (s *Server) WaitForShutdown(ctx context.Context) {
	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
	<-sigCh

	shutdownCtx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	if err := s.Shutdown(shutdownCtx); err != nil {
		klog.ErrorS(err, "Error during shutdown")
	}
}

func (s *Server) setupRoutes() {
	v1 := s.engine.Group("/v1")
	{
		v1.GET("/health", s.handleHealth)
		v1.POST("/agent-runtime", s.handleAgentRuntimeCreate)
		v1.DELETE("/agent-runtime/sessions/:sessionId", s.handleDeleteSandbox)
		v1.POST("/code-interpreter", s.handleCodeInterpreterCreate)
		v1.DELETE("/code-interpreter/sessions/:sessionId", s.handleDeleteSandbox)
	}
}

func generateRSAKey() (*rsa.PrivateKey, error) {
	return rsa.GenerateKey(rand.Reader, 2048)
}

func encodePrivateKeyToPEM(key *rsa.PrivateKey) []byte {
	return pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: x509.MarshalPKCS1PrivateKey(key),
	})
}

func encodePublicKeyToPEM(key *rsa.PublicKey) ([]byte, error) {
	der, err := x509.MarshalPKIXPublicKey(key)
	if err != nil {
		return nil, err
	}
	return pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: der,
	}), nil
}

