func (c *K8sClient) ListExpiredSandboxes(ctx context.Context, before time.Time) ([]map[string]interface{}, error) {
	annotationSelector := fields.OneTermEqualSelector(metav1.ObjectNameField, "").String()
	list, err := c.dynamicCli.Resource(SandboxGVR).List(ctx, metav1.ListOptions{
		FieldSelector: annotationSelector,
	})
	if err != nil {
		return nil, err
	}

	items := make([]map[string]interface{}, 0)
	for _, item := range list.Items {
		annotations := item.GetAnnotations()
		if annotations == nil {
			continue
		}
		expiresAtStr, ok := annotations[ExpiresAtAnnotationKey]
		if !ok {
			continue
		}
		expiresAt, err := time.Parse(time.RFC3339, expiresAtStr)
		if err != nil {
			continue
		}
		if expiresAt.Before(before) {
			items = append(items, item.Object)
		}
	}
	return items, nil
}

