	review := map[string]interface{}{
		"apiVersion": "authentication.k8s.io/v1",
		"kind":       "TokenReview",
		"spec": map[string]interface{}{
			"token": token,
		},
	}

	result, err := c.clientset.Discovery().RESTClient().Post().
		AbsPath("/apis/authentication.k8s.io/v1/tokenreviews").
		Body(review).
		DoRaw(ctx)
	if err != nil {
		return "", fmt.Errorf("token review failed: %w", err)
	}

	klog.V(4).InfoS("Token review result", "result", string(result))
	return string(result), nil
}

