func (s *Server) authMiddlewareFunc() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
				"error": "authorization header required",
			})
			return
		}

		if !strings.HasPrefix(authHeader, "Bearer ") {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
				"error": "invalid authorization header format",
			})
			return
		}

		token := strings.TrimPrefix(authHeader, "Bearer ")

		if cachedToken, ok := s.tokenCache.Get(token); ok {
			c.Set(string(userContextKey), cachedToken)
			c.Next()
			return
		}

		user, err := s.validateServiceAccountToken(c.Request.Context(), token)
		if err != nil {
			klog.ErrorS(err, "Failed to validate token")
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{
				"error": "invalid token",
			})
			return
		}

		s.tokenCache.Set(token, user)
		c.Set(string(userContextKey), user)
		c.Next()
	}
}

func (s *Server) validateServiceAccountToken(ctx context.Context, token string) (string, error) {
	result, err := s.k8sClient.ValidateToken(ctx, token)
	if err != nil {
		return "", err
	}

	klog.V(4).InfoS("Token validation result", "result", result)

	return result, nil
}

func GetUserFromContext(c *gin.Context) string {
	user, exists := c.Get(string(userContextKey))
	if !exists {
		return ""
	}
	return user.(string)
}

func GetTokenFromContext(c *gin.Context) string {
	token, exists := c.Get(string(tokenContextKey))
	if !exists {
		return ""
	}
	return token.(string)
}

