	"flag"
	"fmt"
	"os"
	"os/signal"
	"syscall"

	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/workloadmanager"
)

func main() {
	cfg := workloadmanager.DefaultConfig()

	flag.IntVar(&cfg.Port, "port", cfg.Port, "HTTP server port")
	flag.StringVar(&cfg.Kubeconfig, "kubeconfig", "", "Path to kubeconfig file")
	flag.StringVar(&cfg.MasterURL, "master-url", "", "Kubernetes API server URL")
	flag.StringVar(&cfg.RuntimeClassName, "runtime-class-name", "", "Runtime class name for sandboxes")
	flag.BoolVar(&cfg.EnableTLS, "enable-tls", false, "Enable TLS")
	flag.StringVar(&cfg.TLSCert, "tls-cert", "", "TLS certificate path")
	flag.StringVar(&cfg.TLSKey, "tls-key", "", "TLS key path")
	flag.BoolVar(&cfg.EnableAuth, "enable-auth", false, "Enable authentication")
	flag.BoolVar(&cfg.LeaderElection, "leader-election", false, "Enable leader election")
	flag.StringVar(&cfg.LeaderElectionID, "leader-election-id", cfg.LeaderElectionID, "Leader election ID")
	flag.StringVar(&cfg.MetricsAddr, "metrics-addr", cfg.MetricsAddr, "Metrics server address")
	flag.StringVar(&cfg.HealthProbeAddr, "health-probe-addr", cfg.HealthProbeAddr, "Health probe server address")

	klog.InitFlags(nil)
	flag.Parse()

	klog.InfoS("Starting workload manager", "config", fmt.Sprintf("%+v", cfg))

	server, err := workloadmanager.NewServer(cfg)
	if err != nil {
		klog.ErrorS(err, "Failed to create server")
		os.Exit(1)
	}

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	if err := server.Start(ctx); err != nil {
		klog.ErrorS(err, "Failed to start server")
		os.Exit(1)
	}

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
	<-sigCh

	klog.InfoS("Shutting down workload manager")
	shutdownCtx, shutdownCancel := context.WithTimeout(context.Background(), 10)
	defer shutdownCancel()

	if err := server.Shutdown(shutdownCtx); err != nil {
		klog.ErrorS(err, "Error during shutdown")
		os.Exit(1)
	}

	klog.InfoS("Workload manager stopped")
}

